use config::Config;

/// Tests for Config struct and loading functionality
/// Generated by Agent B for comprehensive coverage of config module

#[test]
fn test_config_default() {
    let config = Config::default();
    assert!(config.upstream_url.is_empty());
    assert!(config.disabled_entities.is_empty());
}


#[test]
fn test_load_valid_config() {
    let temp_file = "/tmp/test_obscura_valid.toml";
    let toml_content = r#"

upstream_url = "http://localhost:8081"
disabled_entities = ["EMAIL", "PHONE"]
"#;
    std::fs::write(temp_file, toml_content).unwrap();

    let config = Config::load_from_file(temp_file).unwrap();
    assert_eq!(config.upstream_url, "http://localhost:8081");
    assert_eq!(config.disabled_entities, vec!["EMAIL", "PHONE"]);

    std::fs::remove_file(temp_file).unwrap();
}

