#[test]
fn test_load_config_with_many_disabled_entities() {
    let temp_file = "/tmp/test_obscura_many_entities.toml";
    let toml_content = r#"

disabled_entities = ["EMAIL", "PHONE", "SSN", "CREDIT_CARD", "DOB", "NAME", "ORG", "LOCATION", "IPV4"]
"#;
    std::fs::write(temp_file, toml_content).unwrap();

    let config = Config::load_from_file(temp_file).unwrap();
    assert_eq!(config.disabled_entities.len(), 9);
    assert!(config.disabled_entities.contains(&"EMAIL".to_string()));
    assert!(config.disabled_entities.contains(&"IPV4".to_string()));

    std::fs::remove_file(temp_file).unwrap();
}

