#[test]
fn test_load_config_with_whitespace_in_entities() {
    let temp_file = "/tmp/test_obscura_whitespace_entities.toml";
    let toml_content = r#"

disabled_entities = ["EMAIL", " PHONE ", "SSN"]
"#;
    std::fs::write(temp_file, toml_content).unwrap();

    let config = Config::load_from_file(temp_file).unwrap();
    assert_eq!(config.disabled_entities.len(), 3);
    assert_eq!(config.disabled_entities[1], " PHONE ");

    std::fs::remove_file(temp_file).unwrap();
}
